INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (2100903263, 'officer_ability_desc_77021', '<color=#309BBF>Past Always Catches Up</color>
Increases <color=#FFB36B>Apex Shred</color> against players by <color=#40FF60>{0:0,#%} ({1:#,#%} at rank {2:#,#})</color> when assigned to the GS-31.

<color=#6BB7FF>Apex Barrier</color> remaining after <color=#FFB36B>Apex Shred</color> is equal to:
<color=#6BB7FF>Apex Barrier</color> / (100% + <color=#FFB36B>Apex Shred</color>).

100% <color=#FFB36B>Apex Shred</color> reduces <color=#6BB7FF>Apex Barrier</color> by 50%.

<color=#B8DEE5>Officer Abilities are activated when assigned to the bridge of a ship</color>.', '2025-08-13 17:11:38');
